class Solution:
    def countBalls(self, lowLimit, highLimit):
        boxes = {}
        for num in range(lowLimit, highLimit + 1):
            s = 0
            x = num
            while x:
                s += x % 10
                x //= 10
            boxes[s] = boxes.get(s, 0) + 1
        return max(boxes.values())

