class Solution:
    def countBalls(self, lowLimit, highLimit):
        from collections import defaultdict
        boxes = defaultdict(int)
        best = 0
        for num in range(lowLimit, highLimit + 1):
            ds = sum(int(c) for c in str(num))
            boxes[ds] += 1
            if boxes[ds] > best:
                best = boxes[ds]
        return best

