var countBalls = function(lowLimit, highLimit) {
    const boxes = new Map();
    let best = 0;
    for (let num = lowLimit; num <= highLimit; num++) {
        let ds = 0, x = num;
        while (x > 0) { ds += x % 10; x = Math.floor(x / 10); }
        const c = (boxes.get(ds) || 0) + 1;
        boxes.set(ds, c);
        if (c > best) best = c;
    }
    return best;
};
